item.aggregated_output:
"""Load-time pipeline validation (FR-5.3, FR-2.3, PRD §8).

Run once when a pipeline is loaded for a run. Three classes of check:

* **Dangling artifact dataflow** (FR-5.3): every ``inputs:``/``artifact:``
  reference must be a seed artifact (``prd.md``/``plan.md``) or produced by an
  earlier step's ``output:``.
* **Adapter capabilities** (FR-2.3): a step that writes the repo cannot bind an
  adapter that can't (e.g. ``api``); a step that needs a schema *warns* if its
  adapter only does best-effort JSON, and *errors* if it does none.
* **Banned flags** (§8): constructing each referenced adapter runs the
  permission-bypass / hook-disabling lint; a violation aborts the load.
"""

from __future__ import annotations

from dataclasses import dataclass, field

from gauntlet.config import BannedFlagError
from gauntlet.engine.config import RunConfig
from gauntlet.engine.execution import get_spec
from gauntlet.engine.pipeline import Pipeline, Step

SEED_ARTIFACTS = frozenset({"prd.md", "plan.md"})


class PipelineValidationError(ValueError):
    def __init__(self, errors: list[str]) -> None:
        super().__init__("pipeline failed validation:\n- " + "\n- ".join(errors))
        self.errors = errors


@dataclass
class ValidationReport:
    errors: list[str] = field(default_factory=list)
    warnings: list[str] = field(default_factory=list)

    def ok(self) -> bool:
        return not self.errors


def validate_pipeline(
    pipeline: Pipeline, config: RunConfig, *, seeds: frozenset[str] = SEED_ARTIFACTS
) -> ValidationReport:
    report = ValidationReport()
    available: set[str] = set(seeds)
    all_ids = {step.id for step in pipeline.all_steps()}
    for stage in pipeline.stages:
        for step in stage.steps:
            _validate_step(step, config, available, report)
            if step.on_fail and step.on_fail.route_to not in all_ids:
                report.errors.append(
                    f"step {step.id!r} on_fail routes to unknown step "
                    f"{step.on_fail.route_to!r}"
                )
            output = step.get("output")
            if output:
                available.add(output)
    if report.errors:
        raise PipelineValidationError(report.errors)
    return report


def _validate_step(
    step: Step, config: RunConfig, available: set[str], report: ValidationReport
) -> None:
    # 1. step type resolves
    try:
        spec = get_spec(step.type)
    except KeyError as exc:
        report.errors.append(str(exc))
        return

    # 2. dangling artifact dataflow (FR-5.3)
    for name in (step.get("inputs", []) or []):
        if name not in available:
            report.errors.append(
                f"step {step.id!r} input {name!r} is not a seed artifact and is "
                "produced by no earlier step (dangling reference, FR-5.3)"
            )
    artifact = step.get("artifact")
    if artifact and artifact not in available:
        report.errors.append(
            f"step {step.id!r} artifact {artifact!r} is not available at this "
            "point (dangling reference, FR-5.3)"
        )

    # 3. agent profile resolution + capabilities (FR-2.3) + banned flags (§8)
    agent_refs = _agent_refs(step, spec.needs_agent)
    for ref in agent_refs:
        if ref not in config.agents:
            report.errors.append(
                f"step {step.id!r} references undefined agent profile {ref!r}"
            )
            continue
        profile = config.profile(ref)
        caps = profile.capabilities()
        if spec.step_requires_repo_write(step) and not caps.repo_write:
            report.errors.append(
                f"step {step.id!r} needs repo-write but agent {ref!r} "
                f"(adapter {profile.adapter!r}) cannot write the repo (FR-2.3)"
            )
        if _step_uses_schema(step, spec):
            if caps.structured_output == "none":
                report.errors.append(
                    f"step {step.id!r} needs structured output but agent {ref!r} "
                    "supports none (FR-2.3)"
                )
            elif caps.structured_output == "best_effort":
                report.warnings.append(
                    f"step {step.id!r} relies on schema output but agent {ref!r} "
                    "is best-effort JSON only; validate-and-retry applies (FR-2.3)"
                )
        try:
            profile.build_adapter()
        except BannedFlagError as exc:
            report.errors.append(
                f"step {step.id!r} agent {ref!r} uses a banned flag: {exc}"
            )
        except Exception as exc:  # construction issues surface as warnings
            report.warnings.append(
                f"step {step.id!r} agent {ref!r} could not be pre-constructed "
                f"({exc}); deferred to runtime"
            )


def _agent_refs(step: Step, needs_agent: bool) -> list[str]:
    refs: list[str] = []
    if step.agent:
        refs.append(step.agent)
    for key in ("message_agent", "reviewer", "triager", "fixer", "confirmer"):
        ref = step.get(key)
        if ref:
            refs.append(ref)
    return refs


def _step_uses_schema(step: Step, spec) -> bool:
    return bool(spec.uses_schema or step.get("findings_schema") or step.get("schema"))

"""Built-in step types: agent_task, shell, human_gate, commit (FR-5, FR-9.2).

The ``adversarial_cycle`` step type (the review→triage→fix→confirm primitive)
is a P4 deliverable and registers there; P3 ships the four primitives the
crash test and switchover need. Control flow (routing, retries, parking,
budget halts) is the orchestrator's; handlers report status only.

Trust model (plan §0 / review F-001): ``shell`` commands come **only** from
human-committed pipeline/config YAML — :func:`render_shell_command` refuses any
template token that is not a ``{{config.*}}`` reference, so agent-authored text
can never be substituted into a command line.
"""

from __future__ import annotations

import re
import subprocess
from pathlib import Path

from gauntlet.engine.commit_format import header_prefix, validate_commit_message
from gauntlet.engine.execution import (
    DONE,
    FAILED,
    PARKED,
    StepContext,
    StepResult,
    StepSpec,
)
from gauntlet.engine import gitops
from gauntlet.engine.pipeline import Step

_CONFIG_TOKEN_RE = re.compile(r"\{\{\s*config\.([a-zA-Z0-9_]+)\s*\}\}")
_ANY_TOKEN_RE = re.compile(r"\{\{.*?\}\}")


# --- shell -------------------------------------------------------------------
def render_shell_command(template: str, config) -> str:
    """Substitute only ``{{config.<key>}}`` tokens; reject anything else.

    Refusing non-config tokens is the engine-side enforcement of the trust
    model: no agent-authored artifact may be interpolated into a shell command.
    """
    def _sub(m: re.Match[str]) -> str:
        key = m.group(1)
        value = getattr(config, key, None)
        if value is None:
            raise ValueError(
                f"shell template references unknown config key {key!r}"
            )
        return str(value)

    rendered = _CONFIG_TOKEN_RE.sub(_sub, template)
    leftover = _ANY_TOKEN_RE.search(rendered)
    if leftover:
        raise ValueError(
            f"shell command may only reference {{{{config.*}}}}; refusing "
            f"to substitute {leftover.group(0)!r} (trust model / review F-001)"
        )
    return rendered


def handle_shell(step: Step, ctx: StepContext) -> StepResult:
    template = step.get("run")
    if not template:
        return StepResult(status=FAILED, notes="shell step has no `run:` command")
    command = render_shell_command(template, ctx.config)
    proc = subprocess.run(
        command,
        shell=True,
        cwd=ctx.repo_root,
        capture_output=True,
        text=True,
    )
    _write_step_log(ctx, "output.txt", _proc_log(command, proc))
    if proc.returncode != 0:
        return StepResult(
            status=FAILED,
            notes=f"`{command}` exited {proc.returncode}",
        )
    return StepResult(status=DONE, notes=f"`{command}` exited 0")


# --- human_gate --------------------------------------------------------------
def handle_human_gate(step: Step, ctx: StepContext) -> StepResult:
    show = step.get("show", []) or []
    return StepResult(
        status=PARKED,
        notes=f"awaiting human decision; review: {', '.join(show) or '(nothing listed)'}",
    )


# --- agent_task --------------------------------------------------------------
def handle_agent_task(step: Step, ctx: StepContext) -> StepResult:
    agent_name = step.agent
    if not agent_name:
        return StepResult(status=FAILED, notes="agent_task step has no `agent:`")
    adapter = ctx.build_adapter(agent_name)
    prompt = _render_prompt(step, ctx)
    schema = _load_schema(step, ctx)
    timeout = step.timeout_s
    if timeout is not None and hasattr(adapter, "timeout_s"):
        adapter.timeout_s = timeout
    result = adapter.run(
        prompt,
        session=ctx.record.session_id,
        schema=schema,
        cwd=ctx.repo_root,
    )
    _write_step_log(ctx, "prompt.md", prompt)
    artifact_writes: dict[str, Path] = {}
    output = step.get("output")
    if output:
        out_path = ctx.artifact_root / output
        ctx.writer.write_text(out_path, result.text)
        artifact_writes[output] = out_path
    return StepResult(
        status=DONE,
        session_id=result.session_id,
        usage=result.usage,
        artifact_writes=artifact_writes,
        notes=f"agent {agent_name!r} completed",
    )


def _render_prompt(step: Step, ctx: StepContext) -> str:
    template_ref = step.get("prompt")
    if template_ref:
        template_path = ctx.repo_root / template_ref
        base = template_path.read_text()
    else:
        base = step.get("prompt_text", "") or ""
    parts = [base]
    for name in step.get("inputs", []) or []:
        path = ctx.artifacts.get(name) or (ctx.artifact_root / name)
        content = Path(path).read_text() if Path(path).exists() else ""
        parts.append(f"\n\n--- input artifact: {name} ---\n{content}")
    if ctx.iteration_item is not None:
        parts.append(f"\n\n--- foreach item [{ctx.iteration_index}] ---\n{ctx.iteration_item}")
    return "".join(parts)


def _load_schema(step: Step, ctx: StepContext) -> dict | None:
    ref = step.get("findings_schema") or step.get("schema")
    if not ref:
        return None
    import json

    return json.loads((ctx.repo_root / ref).read_text())


# --- commit (FR-9.2/9.7) -----------------------------------------------------
def handle_commit(step: Step, ctx: StepContext) -> StepResult:
    repo = ctx.repo_root
    exclude = [ctx.config.run_root]  # never commit / count the run bookkeeping
    message = _commit_message(step, ctx)
    err = validate_commit_message(message)
    if err is not None:
        # message_agent drafting includes a bounded redraft loop in _draft;
        # a literal/exhausted message that still fails is a hard error.
        return StepResult(status=FAILED, notes=f"commit message invalid: {err.reason}")
    prefix = header_prefix(message)

    # Mid-commit resume reconciliation (review F-003): if a prior attempt
    # already created the commit (HEAD moved off the recorded base) but died
    # before recording the SHA, adopt that commit rather than double-committing.
    base = ctx.record.base_sha
    if base and gitops.head_sha(repo) != base and gitops.is_clean(repo, exclude=exclude):
        existing = gitops.head_sha(repo)
        if header_prefix(gitops.commit_message(repo, existing)) == prefix:
            return StepResult(
                status=DONE,
                commit_sha=existing,
                commit_phase=prefix,
                notes="reconciled pre-existing commit after mid-commit interruption",
            )

    if gitops.is_clean(repo, exclude=exclude):
        return StepResult(
            status=FAILED,
            notes="commit step found a clean worktree with nothing to commit",
        )

    agent_name = step.agent or step.get("message_agent") or "builder"
    identity = ctx.config.identity(agent_name)
    sha = gitops.commit_all(repo, message, identity=identity, exclude=exclude)
    return StepResult(
        status=DONE, commit_sha=sha, commit_phase=prefix, notes=f"committed {sha[:10]}"
    )


def _commit_message(step: Step, ctx: StepContext) -> str:
    literal = step.get("message")
    if literal:
        return literal  # human-authored YAML; still format-validated above
    return _draft_commit_message(step, ctx)


def _draft_commit_message(step: Step, ctx: StepContext) -> str:
    """Draft a commit message via the message_agent with bounded redraft.

    The agent sees the diff + plan section (data); the engine validates the
    format and asks for a redraft on violation (FR-9.2). Returns the last draft
    (valid or not) — :func:`handle_commit` makes the accept/reject decision.
    """
    agent_name = step.get("message_agent")
    if not agent_name:
        raise ValueError("commit step needs either `message:` or `message_agent:`")
    adapter = ctx.build_adapter(agent_name)
    diff = gitops.diff_head(ctx.repo_root, exclude=[ctx.config.run_root])
    base_prompt = (
        (ctx.repo_root / step.get("prompt")).read_text()
        if step.get("prompt")
        else _DEFAULT_COMMIT_PROMPT
    )
    phase_hint = step.get("phase", "")
    prompt = (
        f"{base_prompt}\n\nRequired header phase prefix: {phase_hint or '(infer PN)'}\n"
        f"\n--- diff (HEAD) ---\n{diff}\n"
    )
    max_redrafts = int(step.get("max_redrafts", 2))
    message = ""
    for attempt in range(1 + max_redrafts):
        result = adapter.run(prompt, cwd=ctx.repo_root)
        message = result.text.strip()
        if validate_commit_message(message) is None:
            return message
        prompt = (
            f"{base_prompt}\n\nYour previous draft was rejected: "
            f"{validate_commit_message(message).reason}. "
            "Return only the corrected commit message.\n"
            f"\n--- diff (HEAD) ---\n{diff}\n"
        )
    return message


_DEFAULT_COMMIT_PROMPT = (
    "Draft a git commit message for the staged changes. Line 1: an imperative "
    "header prefixed with the phase, e.g. 'P3: <summary>', at most 72 chars. "
    "Then a blank line, then a body explaining what changed and why, the plan "
    "assumption validated, and relevant FR references."
)


# --- helpers -----------------------------------------------------------------
def _proc_log(command: str, proc: subprocess.CompletedProcess) -> str:
    return (
        f"$ {command}\n--- exit {proc.returncode} ---\n"
        f"--- stdout ---\n{proc.stdout}\n--- stderr ---\n{proc.stderr}\n"
    )


def _write_step_log(ctx: StepContext, name: str, text: str) -> None:
    iteration = ctx.record.iteration
    leaf = ctx.record.id if iteration is None else f"{ctx.record.id}.{iteration}"
    ctx.writer.write_text(ctx.steps_dir() / leaf / name, text)


SPECS: dict[str, StepSpec] = {
    "agent_task": StepSpec(
        type="agent_task",
        handler=handle_agent_task,
        needs_agent=True,
        # repo_write / touches_worktree are decided per-step (default True)
    ),
    "shell": StepSpec(
        type="shell",
        handler=handle_shell,
        touches_worktree=True,  # a test/build step can mutate the tree
    ),
    "human_gate": StepSpec(
        type="human_gate",
        handler=handle_human_gate,
    ),
    "commit": StepSpec(
        type="commit",
        handler=handle_commit,
        touches_worktree=True,
    ),
}

"""Thin git wrapper for the engine (FR-9, FR-8 transaction boundary).

The engine executes only human-committed configuration and git operations on
its own behalf — it never substitutes agent-authored text into a command line
(plan §0 trust model / review F-001). These helpers shell out to ``git`` with
explicit, fixed argv; the only model-derived value that reaches git is the
commit *message*, which is passed via a file/`-F`-style stdin path and is
treated as data (format-validated before it is used — see ``commit_format``).
"""

from __future__ import annotations

import subprocess
from dataclasses import dataclass
from pathlib import Path


class GitError(RuntimeError):
    """A git invocation failed. Carries argv + stderr for the manifest/log."""

    def __init__(self, argv: list[str], returncode: int, stderr: str) -> None:
        super().__init__(
            f"git {' '.join(argv)} failed (exit {returncode}): {stderr.strip()}"
        )
        self.argv = argv
        self.returncode = returncode
        self.stderr = stderr


def _run(repo: Path, *args: str, stdin: str | None = None) -> str:
    argv = ["git", "-C", str(repo), *args]
    proc = subprocess.run(
        argv,
        input=stdin,
        capture_output=True,
        text=True,
    )
    if proc.returncode != 0:
        raise GitError(list(args), proc.returncode, proc.stderr)
    return proc.stdout


def is_git_repo(repo: Path) -> bool:
    try:
        _run(repo, "rev-parse", "--git-dir")
        return True
    except GitError:
        return False


def head_sha(repo: Path) -> str:
    return _run(repo, "rev-parse", "HEAD").strip()


def rev_parse(repo: Path, ref: str) -> str:
    return _run(repo, "rev-parse", "--verify", ref).strip()


def current_branch(repo: Path) -> str:
    return _run(repo, "rev-parse", "--abbrev-ref", "HEAD").strip()


def _exclude_pathspec(exclude: list[str] | None) -> list[str]:
    """Build a git pathspec that limits an operation to everything but ``exclude``.

    The engine passes its own run root here: that subtree is bookkeeping
    (manifests, run pointer, transcripts), never part of the work tree, so it
    must be invisible to status/add — otherwise it reads as perpetual "dirt",
    pollutes phase commits, and confuses the base-SHA transaction boundary.
    """
    if not exclude:
        return []
    spec = ["--", "."]
    for e in exclude:
        spec.append(f":(exclude){e}")
        spec.append(f":(exclude){e}/**")
    return spec


def status_porcelain(repo: Path, *, exclude: list[str] | None = None) -> str:
    """Porcelain status; empty string means a clean worktree."""
    return _run(repo, "status", "--porcelain", *_exclude_pathspec(exclude)).strip()


def is_clean(repo: Path, *, exclude: list[str] | None = None) -> bool:
    return status_porcelain(repo, exclude=exclude) == ""


def is_dirty_vs(repo: Path, base_sha: str, *, exclude: list[str] | None = None) -> bool:
    """True if the worktree (tracked + staged + untracked) differs from ``base_sha``.

    The engine's transaction boundary (review F-003) records a step's base SHA
    before any worktree-touching step. On resume it compares against that base:
    a difference means the killed step left partial edits.
    """
    if status_porcelain(repo, exclude=exclude) != "":
        return True
    # No working-tree changes; confirm HEAD still points at the recorded base.
    return head_sha(repo) != base_sha


def branch_exists(repo: Path, branch: str) -> bool:
    try:
        _run(repo, "rev-parse", "--verify", f"refs/heads/{branch}")
        return True
    except GitError:
        return False


def checkout_or_create_branch(repo: Path, branch: str, base: str) -> None:
    """Check out ``branch``, creating it off ``base`` if it does not exist (FR-9.1)."""
    if branch_exists(repo, branch):
        _run(repo, "checkout", branch)
    else:
        _run(repo, "checkout", "-b", branch, base)


@dataclass(frozen=True)
class Identity:
    name: str
    email: str


def commit_all(
    repo: Path,
    message: str,
    *,
    identity: Identity,
    allow_empty: bool = False,
    exclude: list[str] | None = None,
) -> str:
    """Stage everything and commit with an explicit author/committer identity.

    The message is passed on stdin (`-F -`) so no agent-authored text ever
    lands on the argv. ``exclude`` (the run root) is kept out of the commit so
    phase commits carry the work, not engine bookkeeping. Returns the SHA.
    """
    _run(repo, "add", "-A", *_exclude_pathspec(exclude))
    args = [
        "-c",
        f"user.name={identity.name}",
        "-c",
        f"user.email={identity.email}",
        "commit",
        "-F",
        "-",
    ]
    if allow_empty:
        args.append("--allow-empty")
    _run(repo, *args, stdin=message)
    return head_sha(repo)


def commit_subject(repo: Path, sha: str) -> str:
    return _run(repo, "log", "-1", "--format=%s", sha).strip()


def commit_message(repo: Path, sha: str) -> str:
    return _run(repo, "log", "-1", "--format=%B", sha).rstrip("\n")


def range_diff(repo: Path, base: str, head: str) -> str:
    """Diff for the confirm pass / review handoff (`base..head`)."""
    return _run(repo, "diff", f"{base}..{head}")


def diff_head(repo: Path, *, exclude: list[str] | None = None) -> str:
    """Working-tree diff vs HEAD (the change a commit step is about to record)."""
    return _run(repo, "diff", "HEAD", *_exclude_pathspec(exclude))


def is_ancestor(repo: Path, ancestor: str, descendant: str) -> bool:
    try:
        subprocess.run(
            ["git", "-C", str(repo), "merge-base", "--is-ancestor", ancestor, descendant],
            capture_output=True,
            text=True,
            check=True,
        )
        return True
    except subprocess.CalledProcessError:
        return False


def create_ref(repo: Path, ref: str, sha: str) -> None:
    """Create/update an arbitrary ref (used for rollback backup refs, F-010)."""
    _run(repo, "update-ref", ref, sha)


def reset_hard(repo: Path, sha: str) -> None:
    _run(repo, "reset", "--hard", sha)


def clean_untracked(repo: Path, *, exclude: list[str] | None = None) -> None:
    """Remove untracked files/dirs, preserving *ignored* paths (no ``-x``).

    Used after a ``reset_to_base`` rewind so a killed step's untracked partial
    files are discarded too (``reset --hard`` alone leaves them). ``exclude``
    paths are spared — the engine passes its own run root so a reset never wipes
    the run pointer / manifests / authored prd.md living under it.
    """
    args = ["clean", "-fd"]
    for pattern in exclude or []:
        args += ["-e", pattern]
    _run(repo, *args)


def backup_dirty_worktree(
    repo: Path, ref: str, message: str, *, exclude: list[str] | None = None
) -> str:
    """Snapshot the full dirty worktree (tracked + untracked) to a backup ref.

    Captures partial work that ``reset --hard`` would otherwise destroy
    (review F-003 / F-010 safety). ``exclude`` (the run root) is left out so the
    snapshot — and the subsequent reset — never touch the run bookkeeping.
    Returns the backup commit SHA.
    """
    _run(repo, "add", "-A", *_exclude_pathspec(exclude))
    tree = _run(repo, "write-tree").strip()
    parent = head_sha(repo)
    backup = _run(repo, "commit-tree", tree, "-p", parent, "-m", message).strip()
    _run(repo, "update-ref", ref, backup)
    return backup

"""Gauntlet CLI entry point.

P3 adds the run lifecycle (`new`, `run`, `status`, `approve`, `reject`,
`resume`, `abort`, `rollback`); `init`/`doctor` land in P6 per the plan.
"""

from __future__ import annotations

from pathlib import Path

import typer

from gauntlet import __version__

app = typer.Typer(
    name="gauntlet",
    no_args_is_help=True,
    help="Adversarial multi-agent development harness.",
)

judge_app = typer.Typer(no_args_is_help=True, help="Safety judge service (FR-7).")
app.add_typer(judge_app, name="judge")


@app.callback()
def main() -> None:
    """Adversarial multi-agent development harness."""


@app.command()
def version() -> None:
    """Print the installed gauntlet version."""
    typer.echo(f"gauntlet {__version__}")


def _manager() -> "object":
    from gauntlet.engine.run import RunManager

    return RunManager(Path.cwd())


@app.command()
def new(slug: str) -> None:
    """Scaffold runs/<slug>/ with a human-authored PRD stub (FR-8.1, FR-10.1)."""
    path = _manager().new(slug)
    typer.echo(f"scaffolded {path}; author the PRD, then `gauntlet run {slug}`")


@app.command()
def run(
    slug: str,
    pipeline: str = typer.Option("standard", help="Pipeline name under pipelines/."),
    pipeline_file: Path = typer.Option(
        None, help="Explicit pipeline file path (overrides --pipeline)."
    ),
    no_judge: bool = typer.Option(
        False, "--no-judge", help="Do not start the judge (unsafe; testing only)."
    ),
) -> None:
    """Start a run on branch gauntlet/<slug> (FR-8.1)."""
    mgr = _manager()
    path = pipeline_file or (Path.cwd() / "pipelines" / f"{pipeline}.yaml")
    status = mgr.start(slug, path, use_judge=not no_judge)
    typer.echo(f"run status: {status}")


@app.command()
def status(slug: str) -> None:
    """Show the current run status for <slug> (FR-8.1)."""
    man = _manager().status(slug)
    typer.echo(f"{man.slug}: {man.status} (current step: {man.current_step})")
    for rec in man.steps:
        it = f"[{rec.iteration}]" if rec.iteration is not None else ""
        typer.echo(f"  {rec.id}{it}: {rec.status}")


@app.command()
def approve(
    slug: str,
