"""Commit-message format validation (FR-9.2/9.4, CLAUDE.md §7).

The ``commit`` step has the ``message_agent`` draft a message; the engine then
validates it against the enforced format and rejects + redrafts on violation.
The message is *data* (model-authored), so it is validated, never trusted.

Accepted header forms (the phase prefix is structural, not free text):
- ``P3: <imperative summary>``            phase commit (FR-9.2)
- ``P3.1: Address review — <summary>``    fix round (FR-9.4)
- ``P3.r1: Reviewer-applied changes — …`` reviewer-attributed (FR-9.6, P4)
"""

from __future__ import annotations

import re
from dataclasses import dataclass

HEADER_MAX = 72

# P<n>, P<n>.<round>, or P<n>.r<round>, then ": " then a non-empty summary.
_HEADER_RE = re.compile(r"^P\d+(?:\.\d+|\.r\d+)?: \S.*$")


@dataclass(frozen=True)
class FormatError:
    reason: str


def validate_commit_message(message: str) -> FormatError | None:
    """Return ``None`` if the message is well-formed, else a :class:`FormatError`.

    Rules (single source of truth for the engine's reject + redraft loop):
    1. A header line matching the ``PN[.x|.rx]: summary`` shape, ≤ 72 chars.
    2. A blank second line.
    3. A non-empty body (the reasoning — what/why, refs, deferrals).
    """
    if not message or not message.strip():
        return FormatError("commit message is empty")
    # Normalize trailing newline handling; keep interior structure intact.
    lines = message.rstrip("\n").split("\n")
    header = lines[0]
    if len(header) > HEADER_MAX:
        return FormatError(
            f"header is {len(header)} chars; must be ≤ {HEADER_MAX} (FR-9.2)"
        )
    if not _HEADER_RE.match(header):
        return FormatError(
            "header must match 'PN: summary' / 'PN.x: ...' / 'PN.rx: ...' "
            f"(got {header!r})"
        )
    if len(lines) < 2 or lines[1].strip() != "":
        return FormatError("second line must be blank (header/body separator)")
    body = "\n".join(lines[2:]).strip()
    if not body:
        return FormatError("body is empty; the reasoning is part of the deliverable")
    return None


def header_prefix(message: str) -> str | None:
    """Return the ``PN[.x]`` prefix of a well-formed header, else ``None``.

    Used by the mid-commit resume reconciliation (review F-003): match a commit
    that already exists in ``git log`` against the phase the engine intended.
    """
    header = message.rstrip("\n").split("\n", 1)[0]
    m = re.match(r"^(P\d+(?:\.\d+|\.r\d+)?):", header)
    return m.group(1) if m else None

"""Tiny, deterministic expression evaluator for `when:` / `foreach:` (FR-5.4).

Deliberately *not* a Python ``eval``: the orchestrator is a state machine and
must stay inspectable and safe (plan §2 — determinism over cleverness). Only two
shapes are supported, resolved against a plain context dict:

* ``foreach``: a dotted path that must resolve to a list (e.g. ``plan.phases``,
  ``vars.items``).
* ``when``: a dotted path (truthy), optionally ``not <path>``, or
  ``<path> == <literal>`` / ``<path> != <literal>``.
"""

from __future__ import annotations

from typing import Any

_MISSING = object()


def _resolve_path(path: str, context: dict[str, Any]) -> Any:
    node: Any = context
    for part in path.strip().split("."):
        if isinstance(node, dict) and part in node:
            node = node[part]
        else:
            node = getattr(node, part, _MISSING)
        if node is _MISSING:
            return _MISSING
    return node


def resolve_list(expr: str, context: dict[str, Any]) -> list[Any]:
    value = _resolve_path(expr, context)
    if value is _MISSING:
        raise ValueError(f"foreach source {expr!r} does not resolve")
    if not isinstance(value, list):
        raise ValueError(
            f"foreach source {expr!r} resolved to {type(value).__name__}, not a list"
        )
    return value


def _parse_literal(token: str) -> Any:
    token = token.strip()
    if token in ("true", "True"):
        return True
    if token in ("false", "False"):
        return False
    if (token.startswith('"') and token.endswith('"')) or (
        token.startswith("'") and token.endswith("'")
    ):
        return token[1:-1]
    try:
        return int(token)
    except ValueError:
        return token


def eval_when(expr: str | None, context: dict[str, Any]) -> bool:
    if expr is None:
        return True
    expr = expr.strip()
    for op in ("==", "!="):
        if op in expr:
            lhs, rhs = expr.split(op, 1)
            left = _resolve_path(lhs.strip(), context)
            right = _parse_literal(rhs)
            left = None if left is _MISSING else left
            return (left == right) if op == "==" else (left != right)
    if expr.startswith("not "):
        value = _resolve_path(expr[4:].strip(), context)
        return not (value if value is not _MISSING else None)
    value = _resolve_path(expr, context)
    return bool(value if value is not _MISSING else None)

"""CodexAdapter: drives `codex exec` non-interactively (PRD §4.1).

Verified against codex-cli 0.139.0 (see the doctor pin file): `--json` JSONL
events, `--output-schema <file>`, `-o/--output-last-message`, `-s/--sandbox
read-only|workspace-write`, prompt via stdin with `-`, and `codex exec resume
<session>`. Note: 0.139.0 has no `--full-auto` on `exec` (the PRD/plan mention
it); exec mode is already non-interactive and the sandbox flag governs write
access — recorded in the pin file and BOOTSTRAP-NOTES.
"""

from __future__ import annotations

import json
import tempfile
from pathlib import Path
from typing import Any

from gauntlet.adapters._structured import validate_schema
from gauntlet.adapters.base import (
    AdapterCapabilities,
    AgentFailedError,
    AgentResult,
    AgentTimeoutError,
    MalformedOutputError,
    Usage,
)
from gauntlet.adapters.process import ProcessOutput, run_with_timeout
from gauntlet.config import lint_flags

DEFAULT_TIMEOUT_S = 600.0


class CodexAdapter:
    name = "codex"
    capabilities = AdapterCapabilities(
        repo_write=True, structured_output="native", resume=True
    )

    def __init__(
        self,
        *,
        model: str | None = None,
        sandbox: str = "read-only",
        skip_git_repo_check: bool = False,
        executable: str = "codex",
        timeout_s: float = DEFAULT_TIMEOUT_S,
        base_flags: list[str] | None = None,
    ) -> None:
        self.model = model
        self.sandbox = sandbox
        self.skip_git_repo_check = skip_git_repo_check
        self.executable = executable
        self.timeout_s = timeout_s
        self.base_flags = list(base_flags or [])
        lint_flags(self._build_argv(session=None, schema_path=None, output_path=None))

    def run(
        self,
        prompt: str,
        *,
        session: str | None = None,
        schema: dict | None = None,
        cwd: Path | None = None,
        extra_flags: list[str] | None = None,
    ) -> AgentResult:
        with tempfile.TemporaryDirectory(prefix="gauntlet-codex-") as tmp:
            schema_path: Path | None = None
            if schema is not None:
                schema_path = Path(tmp) / "output-schema.json"
                schema_path.write_text(json.dumps(schema))
            output_path = Path(tmp) / "last-message.txt"
            argv = self._build_argv(
                session=session, schema_path=schema_path, output_path=output_path
            )
            argv += extra_flags or []
            argv.append("-")  # prompt on stdin
            lint_flags(argv)
            out = run_with_timeout(
                argv, timeout_s=self.timeout_s, stdin_text=prompt, cwd=cwd
            )
            last_message = (
                output_path.read_text() if output_path.exists() else None
            )
        if out.timed_out:
            raise AgentTimeoutError(
                f"codex killed after {self.timeout_s}s timeout",
                partial=self._partial_result(out),
            )
        return self._parse(out, schema=schema, last_message=last_message)

    # -- command construction -------------------------------------------------

    def _build_argv(
        self,
        *,
        session: str | None,
        schema_path: Path | None,
        output_path: Path | None,
    ) -> list[str]:
        argv = [self.executable, "exec"]
        if session:
            argv += ["resume", session]
        argv.append("--json")
        if self.model:
            argv += ["--model", self.model]
        if session:
            # `exec resume` accepts no --sandbox flag (verified on 0.139.0);
            # the config-override spelling keeps the sandbox pinned on resume.
            argv += ["-c", f'sandbox_mode="{self.sandbox}"']
        else:
            argv += ["--sandbox", self.sandbox]
        if self.skip_git_repo_check:
            argv.append("--skip-git-repo-check")
        if schema_path is not None:
            argv += ["--output-schema", str(schema_path)]
        if output_path is not None:
            argv += ["--output-last-message", str(output_path)]
        argv += self.base_flags
        return argv

    # -- output parsing --------------------------------------------------------

    def _parse(
        self, out: ProcessOutput, *, schema: dict | None, last_message: str | None
    ) -> AgentResult:
        events = self._decode_events(out.stdout, strict=True, out=out)
        # Fail closed on reported failure, even when output parses (F-001).
        failure = self._failure_marker(out, events)
        if failure:
            raise AgentFailedError(
                f"codex reported failure: {failure}; stderr: {out.stderr[:500]}",
                partial=self._partial_result(out),
            )
        text = last_message if last_message is not None else self._last_agent_message(events)
        if text is None:
            raise MalformedOutputError(
                f"no agent message in codex output (exit {out.exit_code}); "
                f"stderr: {out.stderr[:500]}",
                partial=self._partial_result(out),
            )
        structured: Any | None = None
        if schema is not None:
            try:
                structured = json.loads(text)
                validate_schema(structured, schema)
            except (json.JSONDecodeError, ValueError) as exc:
                raise MalformedOutputError(
                    f"codex --output-schema response failed to parse/validate: {exc}",
                    partial=AgentResult(
                        text=text,
                        session_id=self._thread_id(events),
                        raw_events=events,
                        exit_code=out.exit_code,
                    ),
                ) from exc
        return AgentResult(
            text=text,
            structured=structured,
            session_id=self._thread_id(events),
            usage=self._extract_usage(events),
            raw_events=events,
            exit_code=out.exit_code,
        )

    def _decode_events(
        self, stdout: str, *, strict: bool, out: ProcessOutput | None = None
    ) -> list[dict[str, Any]]:
        events: list[dict[str, Any]] = []
        for line in stdout.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                events.append(json.loads(line))
            except json.JSONDecodeError as exc:
                # Fail closed (F-002): with --json, codex logs go to stderr,
                # so a non-JSON stdout line means the event contract broke.
                # Lenient mode is only for building checkpointable partials.
                if strict:
                    raise MalformedOutputError(
                        f"non-JSON line in codex --json output: {line[:200]!r}",
                        partial=self._partial_result(out)
                        if out is not None
                        else None,
                    ) from exc
                events.append({"type": "gauntlet.unparsed_line", "line": line})
        return events

    @staticmethod
    def _failure_marker(
        out: ProcessOutput, events: list[dict[str, Any]]
    ) -> str | None:
        if out.exit_code != 0:
            return f"exit code {out.exit_code}"
        for event in events:
            if event.get("type") in ("turn.failed", "error"):
                detail = event.get("error") or event.get("message") or event
                return f"{event['type']} event: {str(detail)[:300]}"
        return None

    @staticmethod
    def _thread_id(events: list[dict[str, Any]]) -> str | None:
        for event in events:
            if event.get("type") == "thread.started" and event.get("thread_id"):
                return event["thread_id"]
        return None

    @staticmethod
    def _last_agent_message(events: list[dict[str, Any]]) -> str | None:
        for event in reversed(events):
            if event.get("type") == "item.completed":
                item = event.get("item") or {}
                if item.get("type") == "agent_message" and item.get("text"):
                    return item["text"]
        return None

    @staticmethod
    def _extract_usage(events: list[dict[str, Any]]) -> Usage | None:
        totals: dict[str, int] = {}
        for event in events:
            if event.get("type") == "turn.completed" and event.get("usage"):
                for key, value in event["usage"].items():
                    if isinstance(value, int):
                        totals[key] = totals.get(key, 0) + value
        if not totals:
            return None
        # codex reports tokens but no cost: degraded path per PRD §12 Q3.
        return Usage(
            input_tokens=totals.get("input_tokens"),
            output_tokens=totals.get("output_tokens"),
            cached_input_tokens=totals.get("cached_input_tokens"),
            cost_usd=None,
        )

    def _partial_result(self, out: ProcessOutput) -> AgentResult:
        events = self._decode_events(out.stdout, strict=False)
        return AgentResult(
            text=self._last_agent_message(events) or "",
            session_id=self._thread_id(events),
            usage=self._extract_usage(events),
            raw_events=events
            + [{"type": "gauntlet.stderr", "stderr": out.stderr}],
            exit_code=out.exit_code if out.exit_code is not None else -1,
        )

"""ClaudeCodeAdapter: drives `claude -p` headlessly (PRD §4.1).

Verified against claude 2.1.172 (see the doctor pin file): `--output-format
json|stream-json`, `--resume <session>`, `--model`, `--append-system-prompt`,
`--allowedTools`/`--disallowedTools`, `--tools` (empty string disables all
tools), `--permission-mode`, and native structured output via `--json-schema`.
Permission-bypass flags are rejected by the §8 lint, never merely avoided.
"""

from __future__ import annotations

import json
from pathlib import Path
from typing import Any

from gauntlet.adapters._structured import extract_json, validate_schema
from gauntlet.adapters.base import (
    AdapterCapabilities,
    AdapterError,
    AgentFailedError,
    AgentResult,
    AgentTimeoutError,
    MalformedOutputError,
    Usage,
)
from gauntlet.adapters.process import ProcessOutput, run_with_timeout
from gauntlet.config import lint_flags

DEFAULT_TIMEOUT_S = 600.0


class ClaudeCodeAdapter:
    name = "claude-code"
    capabilities = AdapterCapabilities(
        repo_write=True,
        # claude 2.1.172 grew a native --json-schema flag; the PRD assumed
        # best-effort. Verified by the contract suite and pinned.
        structured_output="native",
        resume=True,
    )

    def __init__(
        self,
        *,
        model: str | None = None,
        permission_mode: str | None = None,
        allowed_tools: list[str] | None = None,
        disallowed_tools: list[str] | None = None,
        tools: list[str] | None = None,
        append_system_prompt: str | None = None,
        output_format: str = "json",
        executable: str = "claude",
        timeout_s: float = DEFAULT_TIMEOUT_S,
        base_flags: list[str] | None = None,
    ) -> None:
        if output_format not in ("json", "stream-json"):
            raise ValueError(f"unsupported output_format {output_format!r}")
        self.model = model
        self.permission_mode = permission_mode
        self.allowed_tools = allowed_tools
        self.disallowed_tools = disallowed_tools
        self.tools = tools
        self.append_system_prompt = append_system_prompt
        self.output_format = output_format
        self.executable = executable
        self.timeout_s = timeout_s
        self.base_flags = list(base_flags or [])
        lint_flags(self._build_argv("", session=None, schema=None))

    def run(
        self,
        prompt: str,
        *,
        session: str | None = None,
        schema: dict | None = None,
        cwd: Path | None = None,
        extra_flags: list[str] | None = None,
    ) -> AgentResult:
        argv = self._build_argv(prompt, session=session, schema=schema)
        argv += extra_flags or []
        lint_flags(argv)
        out = run_with_timeout(
            argv, timeout_s=self.timeout_s, stdin_text=prompt, cwd=cwd
        )
        if out.timed_out:
            raise AgentTimeoutError(
                f"claude killed after {self.timeout_s}s timeout",
                partial=self._partial_result(out),
            )
        result = self._parse(out, schema=schema)
        return result

    # -- command construction -------------------------------------------------

    def _build_argv(
        self, prompt: str, *, session: str | None, schema: dict | None
    ) -> list[str]:
        argv = [self.executable, "-p", "--output-format", self.output_format]
        if self.output_format == "stream-json":
            argv.append("--verbose")  # required by claude for stream-json in -p mode
        if self.model:
            argv += ["--model", self.model]
        if self.permission_mode:
            argv += ["--permission-mode", self.permission_mode]
        if self.allowed_tools is not None:
            argv += ["--allowedTools", ",".join(self.allowed_tools)]
        if self.disallowed_tools is not None:
            argv += ["--disallowedTools", ",".join(self.disallowed_tools)]
        if self.tools is not None:
            argv += ["--tools", ",".join(self.tools)]  # "" disables all tools
        if self.append_system_prompt:
            argv += ["--append-system-prompt", self.append_system_prompt]
        if session:
            argv += ["--resume", session]
        if schema is not None:
            argv += ["--json-schema", json.dumps(schema)]
        argv += self.base_flags
        return argv

    # -- output parsing --------------------------------------------------------

    def _parse(self, out: ProcessOutput, *, schema: dict | None) -> AgentResult:
        events = self._decode_events(out, strict=True)
        result_event = next(
            (e for e in reversed(events) if e.get("type") == "result"), None
        )
        partial = AgentResult(
            text=(result_event or {}).get("result") or "",
            session_id=(result_event or {}).get("session_id")
            or next((e["session_id"] for e in events if e.get("session_id")), None),
            usage=self._extract_usage(result_event or {}),
            raw_events=events,
            exit_code=out.exit_code,
        )
        # Fail closed on reported failure, even when output parses (F-001).
        failure = self._failure_marker(out, result_event)
        if failure:
            raise AgentFailedError(
                f"claude reported failure: {failure}; stderr: {out.stderr[:500]}",
                partial=partial,
            )
        if result_event is None:
            raise MalformedOutputError(
                f"no result event in claude output (exit {out.exit_code}); "
                f"stderr: {out.stderr[:500]}",
                partial=partial,
            )
        text = result_event.get("result") or ""
        structured = self._extract_structured(result_event, text, schema)
        return partial.model_copy(update={"text": text, "structured": structured})

    @staticmethod
    def _failure_marker(out: ProcessOutput, result_event: dict | None) -> str | None:
        if out.exit_code != 0:
            return f"exit code {out.exit_code}"
        if result_event is not None:
            if result_event.get("is_error"):
                return f"is_error=true (subtype: {result_event.get('subtype')!r})"
            subtype = result_event.get("subtype") or ""
            if subtype.startswith("error"):
                return f"subtype {subtype!r}"
        return None

    def _decode_events(
        self, out: ProcessOutput, *, strict: bool
    ) -> list[dict[str, Any]]:
        if self.output_format == "json":
            try:
                obj = json.loads(out.stdout)
            except json.JSONDecodeError as exc:
                raise MalformedOutputError(
                    f"claude --output-format json did not return JSON: {exc}; "
                    f"stdout head: {out.stdout[:500]!r}",
                    partial=self._raw_partial(out),
                ) from exc
            return obj if isinstance(obj, list) else [obj]
        events: list[dict[str, Any]] = []
        for line in out.stdout.splitlines():
            line = line.strip()
            if not line:
                continue
            try:
                events.append(json.loads(line))
            except json.JSONDecodeError as exc:
                # Fail closed (F-002): with stream-json, logs go to stderr, so
                # a non-JSON stdout line means the output contract broke.
                # Lenient mode is only for building checkpointable partials.
                if strict:
                    raise MalformedOutputError(
                        f"non-JSON line in claude stream-json output: {line[:200]!r}",
                        partial=self._raw_partial(out),
                    ) from exc
                events.append({"type": "gauntlet.unparsed_line", "line": line})
        return events

    def _extract_structured(
        self, result_event: dict, text: str, schema: dict | None
    ) -> Any | None:
        if schema is None:
            return None
        # claude 2.1.x surfaces --json-schema output as `structured_output`
        # on the result event; fall back to parsing the result text.
        structured = result_event.get("structured_output")
        if structured is None:
            try:
                structured = extract_json(text)
            except ValueError as exc:
                raise MalformedOutputError(
                    f"schema requested but result is not parseable JSON: {exc}",
                    partial=self._partial_from_event(result_event),
                ) from exc
        try:
            validate_schema(structured, schema)
        except ValueError as exc:
            raise MalformedOutputError(
                str(exc), partial=self._partial_from_event(result_event)
            ) from exc
        return structured

    @staticmethod
    def _extract_usage(result_event: dict) -> Usage | None:
        usage = result_event.get("usage") or {}
        cost = result_event.get("total_cost_usd")
        if not usage and cost is None:
            return None
        cached = usage.get("cache_read_input_tokens")
        return Usage(
            input_tokens=usage.get("input_tokens"),
            output_tokens=usage.get("output_tokens"),
            cached_input_tokens=cached,
            cost_usd=cost,  # None => tokens-only degraded path (PRD §12 Q3)
        )

    def _partial_result(
        self, out: ProcessOutput, events: list[dict[str, Any]] | None = None
    ) -> AgentResult:
        if events is None:
            try:
                events = self._decode_events(out, strict=False)
            except AdapterError:
                events = [{"type": "gauntlet.raw_stdout", "stdout": out.stdout}]
        return AgentResult(
            text="",
            raw_events=events
            + [{"type": "gauntlet.stderr", "stderr": out.stderr}],
            exit_code=out.exit_code if out.exit_code is not None else -1,
        )

    @staticmethod
    def _raw_partial(out: ProcessOutput) -> AgentResult:
        return AgentResult(
            text="",
            raw_events=[
                {"type": "gauntlet.raw_stdout", "stdout": out.stdout},
                {"type": "gauntlet.stderr", "stderr": out.stderr},
            ],
            exit_code=out.exit_code if out.exit_code is not None else -1,
        )

    @staticmethod
    def _partial_from_event(result_event: dict) -> AgentResult:
        return AgentResult(
            text=result_event.get("result") or "",
            session_id=result_event.get("session_id"),
            raw_events=[result_event],
            exit_code=0,
        )

"""Commit-format validator (FR-9.2/9.4)."""

from gauntlet.engine.commit_format import header_prefix, validate_commit_message

GOOD = "P3: Add the pipeline engine\n\nWhat changed and why. Validates FR-5."


def test_accepts_well_formed_phase_commit():
    assert validate_commit_message(GOOD) is None


def test_accepts_fix_round_and_reviewer_headers():
    assert validate_commit_message("P3.1: Address review — fix x\n\nF-001: ...") is None
    assert validate_commit_message("P3.r1: Reviewer-applied changes — y\n\nbody") is None


def test_rejects_overlong_header():
    long = "P3: " + "x" * 80
    err = validate_commit_message(long + "\n\nbody")
    assert err and "72" in err.reason


def test_rejects_missing_phase_prefix():
    err = validate_commit_message("Add a thing\n\nbody")
    assert err and "PN" in err.reason


def test_rejects_non_blank_second_line():
    err = validate_commit_message("P1: ok\nbody immediately")
    assert err and "blank" in err.reason


def test_rejects_empty_body():
    err = validate_commit_message("P1: ok\n\n   ")
    assert err and "body" in err.reason


def test_rejects_empty_message():
    assert validate_commit_message("") is not None


def test_header_prefix_extraction():
    assert header_prefix(GOOD) == "P3"
    assert header_prefix("P3.1: x\n\ny") == "P3.1"
    assert header_prefix("P3.r2: x\n\ny") == "P3.r2"
    assert header_prefix("nope") is None
"""`when:` / `foreach:` evaluator (FR-5.4)."""

import pytest

from gauntlet.engine.expr import eval_when, resolve_list


def test_when_none_is_true():
    assert eval_when(None, {}) is True


def test_when_truthy_path():
    assert eval_when("vars.ready", {"vars": {"ready": True}}) is True
    assert eval_when("vars.ready", {"vars": {"ready": False}}) is False
    assert eval_when("vars.missing", {"vars": {}}) is False


def test_when_negation():
    assert eval_when("not vars.skip", {"vars": {"skip": False}}) is True
    assert eval_when("not vars.skip", {"vars": {"skip": True}}) is False


def test_when_equality():
    ctx = {"vars": {"mode": "code_review"}}
    assert eval_when("vars.mode == 'code_review'", ctx) is True
    assert eval_when("vars.mode == 'document'", ctx) is False
    assert eval_when("vars.mode != 'document'", ctx) is True


def test_when_int_equality():
    assert eval_when("vars.n == 2", {"vars": {"n": 2}}) is True


def test_resolve_list():
    assert resolve_list("plan.phases", {"plan": {"phases": [1, 2, 3]}}) == [1, 2, 3]


def test_resolve_list_rejects_non_list():
    with pytest.raises(ValueError):
        resolve_list("vars.x", {"vars": {"x": "nope"}})


def test_resolve_list_missing():
    with pytest.raises(ValueError):
        resolve_list("vars.absent", {"vars": {}})

"""ApiAdapter: LiteLLM completions for non-agentic tasks (PRD §4.1).

Used for classification work that needs no repo access: triage, judge LLM
fallback, retro summarization, commit messages. Structured output is enforced
locally — schema embedded in the prompt, response parsed and validated with
jsonschema, bounded validate-and-retry with error feedback (FR-3.4
groundwork) — so behavior is identical across providers rather than
depending on per-provider response_format support.
"""

from __future__ import annotations

from pathlib import Path
from typing import Any

from gauntlet.adapters._structured import (
    extract_json,
    schema_instruction,
    validate_schema,
)
from gauntlet.adapters.base import (
    AdapterCapabilities,
    AgentResult,
    MalformedOutputError,
    UnsupportedFeatureError,
    Usage,
)

DEFAULT_TIMEOUT_S = 120.0


class ApiAdapter:
    name = "api"
    capabilities = AdapterCapabilities(
        repo_write=False, structured_output="native", resume=False
    )

    def __init__(
        self,
        *,
        model: str,
        max_schema_retries: int = 2,
        timeout_s: float = DEFAULT_TIMEOUT_S,
        temperature: float | None = None,
        max_tokens: int | None = None,
    ) -> None:
        self.model = model
        self.max_schema_retries = max_schema_retries
        self.timeout_s = timeout_s
        self.temperature = temperature
        self.max_tokens = max_tokens

    def run(
        self,
        prompt: str,
        *,
        session: str | None = None,
        schema: dict | None = None,
        cwd: Path | None = None,  # accepted for interface parity; unused
        extra_flags: list[str] | None = None,  # meaningless for an API call
    ) -> AgentResult:
        if session is not None:
            raise UnsupportedFeatureError(
                "ApiAdapter has no session continuity (capabilities.resume=False)"
            )
        if extra_flags:
            raise UnsupportedFeatureError(
                "ApiAdapter takes no CLI flags; configure model parameters instead"
            )
        messages = [{"role": "user", "content": self._render(prompt, schema)}]
        raw_events: list[dict[str, Any]] = []
        usage_total = Usage(input_tokens=0, output_tokens=0, cost_usd=None)
        last_error: str | None = None
        text = ""
        for _attempt in range(1 + self.max_schema_retries):
            if last_error is not None:
                messages.append({"role": "assistant", "content": text})
                messages.append(
                    {
                        "role": "user",
                        "content": (
                            "Your previous response was rejected: "
                            f"{last_error}. Respond again with only the "
                            "corrected JSON."
                        ),
                    }
                )
            response = self._complete(messages)
            raw_events.append(_response_to_dict(response))
            text = response.choices[0].message.content or ""
            _accumulate_usage(usage_total, response)
            if schema is None:
                return self._result(text, None, usage_total, raw_events)
            try:
                structured = extract_json(text)
                validate_schema(structured, schema)
            except ValueError as exc:
                last_error = str(exc)
                continue
            return self._result(text, structured, usage_total, raw_events)
        raise MalformedOutputError(
            f"schema validation failed after {1 + self.max_schema_retries} "
            f"attempts: {last_error}",
            partial=self._result(text, None, usage_total, raw_events),
        )

    @staticmethod
    def _render(prompt: str, schema: dict | None) -> str:
        return prompt + schema_instruction(schema) if schema else prompt

    def _complete(self, messages: list[dict[str, str]]) -> Any:
        import litellm  # deferred: heavy import, only needed on the API path

        kwargs: dict[str, Any] = {
            "model": self.model,
            "messages": messages,
            "timeout": self.timeout_s,
        }
        if self.temperature is not None:
            kwargs["temperature"] = self.temperature
        if self.max_tokens is not None:
            kwargs["max_tokens"] = self.max_tokens
        return litellm.completion(**kwargs)

    @staticmethod
    def _result(
        text: str,
        structured: Any | None,
        usage: Usage,
        raw_events: list[dict[str, Any]],
    ) -> AgentResult:
        return AgentResult(
            text=text,
            structured=structured,
            session_id=None,
            usage=usage,
            raw_events=raw_events,
            exit_code=0,
        )


def _accumulate_usage(total: Usage, response: Any) -> None:
    usage = getattr(response, "usage", None)
    if usage is not None:
        total.input_tokens = (total.input_tokens or 0) + (
            getattr(usage, "prompt_tokens", 0) or 0
        )
        total.output_tokens = (total.output_tokens or 0) + (
            getattr(usage, "completion_tokens", 0) or 0
        )
    cost = _completion_cost(response)
    if cost is not None:
        total.cost_usd = (total.cost_usd or 0.0) + cost
    # if cost stays None: tokens-only degraded path (PRD §12 Q3)


def _completion_cost(response: Any) -> float | None:
    import litellm

    try:
        return litellm.completion_cost(completion_response=response)
    except Exception:
        return None


def _response_to_dict(response: Any) -> dict[str, Any]:
    for attr in ("model_dump", "dict", "to_dict"):
        method = getattr(response, attr, None)
        if callable(method):
            try:
                return {"type": "api.completion", "response": method()}
            except Exception:
                continue
    return {"type": "api.completion", "response": repr(response)}
